import { Kernel } from '@semantic-kernel/core';
import { OpenAIChatCompletion } from '@semantic-kernel/connectors-ai-openai';

const kernel = Kernel.create({
  chat: {
    OpenAIChatCompletion('gpt-4o')
  }
});

// Import content plugins
await kernel.importPluginFromDirectory('./plugins/brand-voice');
await kernel.importPluginFromDirectory('./plugins/fact-check');

const result = await kernel.invoke('BrandVoice', 'enforce_tone', {
  input: 'Draft blog post about AI ethics',
  brandGuidelines: 'Professional, optimistic tone'
});

async def generate_content(kernel, topic):
    # Research
    research = await kernel.invoke('ResearchPlugin', 'web_search', {'query': topic})

    # Draft
    draft = await kernel.invoke('WriterPlugin', 'generate_draft', {
        'research': research, 'topic': topic
    })

    # Brand enforcement
    branded = await kernel.invoke('BrandPlugin', 'enforce_voice', {
        'content': draft, 'guidelines': 'professional_tech'
    })

    # Fact check
    verified = await kernel.invoke('FactCheckPlugin', 'verify_facts', {
        'content': branded
    })

    return verified

import { SequentialPlanner } from '@semantic-kernel/planners';

const planner = kernel.addService(SequentialPlanner);

const plan = await planner.createPlan({
  goal: `Create blog post about ${topic} that:
  1. Researches current trends
  2. Drafts 800 words
  3. Enforces our brand voice
  4. Fact-checks all claims
  5. Optimizes for SEO`
});

const result = await plan.invokeAsync();

